script.text:
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  var o = f.getItem('maxLength');
  o.value = o.maxLength;
  var a = ['ma_ct'];
  if (!f._extensions) {
    f.request('GetDefaultValue', 'SetDefaultValue', a);
    onChange$Form$Unit(f.getItem('ma_dvcs'));
  } else {
    setReferenceValue(f, a);
    setItemAllowNulls(f, 'ma_nk', f._allowNulls);
  }
  f.setReferenceKeyFilter('ma_ct');
  f.setReferenceKeyFilter('ma_nk');
  if (f.getItemValue('ma_nk')) {
    var g = f.grid;
    f.setItemValues('mau_so, ky_hieu', [g._$form, g._$series]);
  }
  if (!f._$showDebugMode) add$FormDebugMode$KeyupHandler(f);
  onChange$Form$VoucherCode(f.getItem('ma_ct'));
  onChange$Form$Type(f.getItem('xu_ly'));
  f.live(f.getItem('xu_ly'));
}
function close$VoucherFilter$(f) {
  try {remove$FormDebugMode$KeyupHandler(f);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, dFrom = f.getItem('ngay_ct1').value, dTo = f.getItem('ngay_ct2').value, v = (f.getItemValue('ma_ct') == 'PXA' ? 1 : 0);
      g._$unit = f.getItemValue('ma_dvcs');
      g._$unitName = f.getItemValue('ten_dvcs%l');
      g._$dFrom = f.getItemValue('ngay_ct1');
      g._$dTo = f.getItemValue('ngay_ct2');
      g._$voucherCode = f.getItemValue('ma_ct');
      g._$process = f.getItemValue('xu_ly');
      g._$processOriginal = f.getItemValue('xu_ly');
      g._$resign = parseInt(f.getItemValue('adjust_mode'));
      g._$debugMode = f.getItemValue('debug_mode');

      g._$voucherBook = $func.trim(f.getItemValue('ma_nk'));
      g._$form = f.getItemValue('mau_so');
      g._$series = f.getItemValue('ky_hieu');

      g._alterTitle = [null, [['%u1', g._$unit, true], ['%u2', g._$unitName, true], ['%d1', dFrom, true], ['%d2', dTo, true], ['%s1', g._$voucherCode, true], ['%s2', f.getItemValue('ten_ct%l'), true]]];
      g._hiddenFields = [{Fields: 'ma_kh, ten_kh', Value: (!v)}, {Fields: 'ma_kho, ma_khon', Value: (v)}];
      g._$i = g._getColumnOrder('stt_rec');
      g._$y = g._getColumnOrder('ngay_ct');
      if (g._$k != null) g._$k = [], g._$ld = [], g._$lvd = [], g._$c = [];
      break;
    case 'EIVoucherBook':
      f.setItemValues('mau_so, ky_hieu', [result[0].Value, result[1].Value]);
      break;
    case 'SetDefaultValue':
      if (result[0].Value == '') f.setItemValue('ma_ct', '');
        else f.setItemControlBehavior('ten_ct%l', result[0].Value, null, true);
      break;
    case 'GetSupplier':
      f._allowNulls = result[0].Value;
      setItemAllowNulls(f, 'ma_nk', result[0].Value);
      f.grid._allowPreview = result[1].Value;
      break;
    default:
      break;
  }
}
function onChange$Form$Type(o) {
  var f = o.parentForm, v = (f.getItemValue('xu_ly') == '1');
  setItemAllowNulls(f, 'ma_nk', v);
}
function onChange$Form$VoucherCode(o) {
  var f = o.parentForm;
  window.setTimeout(String.format('onFocus$Form$VoucherCode(\'{0}\');', f._id), 2);
}
function onFocus$Form$VoucherCode(id) {
  var f = $find(id), v = (f.getItem('ma_ct').value == 'PXA'), t1 = f.getItem('ma_kh'), t2 = f.getItem('ma_kho');
  setItemLive(t1, t2, !v);
  setItemDisable(f, 'ma_kho, ma_khon', v);
  setFieldsEmpty(f, 'ma_kh, ten_kh%l', v);
  setItemDisable(f, 'ma_kh', !v);
  setFieldsEmpty(f, 'ma_kho, ten_kho_xuat%l, ma_khon, ten_khon%l', !v);
}
function onChange$Form$Unit(o) {
  var f = o.parentForm;
  f.setReferenceKeyFilter('ma_nk');
  f.request('GetSupplier', 'GetSupplier', ['ma_dvcs']);
}
function onChange$Form$EIVoucherBook(o) {
  var f = o.parentForm;
  if (!$func.trim(o.value)) f.setItemValues('mau_so, ky_hieu', ['', '']);
    else f.request('EIVoucherBook', 'EIVoucherBook', ['ma_nk']);
}
function set$Form$DefaultValue(f) {
  if (!f._$showDebugMode) setObjectFormHidden$DebugMode(f, true);
  f.setItemControlBehavior('ma_dvcs', f._unitCode, f._unitName, null);
}
function setReferenceValue(f, a) {
  for (var i = 0; i < a.length; i++) {
    var r = $func.findField(a[i], f._fields).ItemReference;
    f.setItemValue(r, $func.findMemvar(r, f._extensions).NewValue);
  }
}
function setItemAllowNulls(f, c, v) {
  var a = c.split(','), o, grandNode;
  for (var i = 0; i < a.length; i++) {
    if ($func.trim(a[i]) != '') {
      o = f.getItem($func.trim(a[i]));
      o.field.AllowNulls = !v
      grandNode = o.parentNode.parentNode;
      if (v) {
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      }
      else Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
    }
  }
}
function add$FormDebugMode$KeyupHandler(f) {
  if (f._$admin) {
    f._on$FormDebugMode$KeyupHandler = Function.createDelegate(f, on$FormDebugMode$KeyupHandler);
    $addHandler(document, 'keyup', f._on$FormDebugMode$KeyupHandler);
  }
}
function remove$FormDebugMode$KeyupHandler(f) {
  if (f._on$FormDebugMode$KeyupHandler) {
    $removeHandler(document, 'keyup', f._on$FormDebugMode$KeyupHandler);
    f._on$FormDebugMode$KeyupHandler = null;
  }
}
function on$FormDebugMode$KeyupHandler(e) {
  if ((e.ctrlKey) && (e.altKey) && (e.keyCode == 113)) {
    setObjectFormHidden$DebugMode(this, false);
  };
}
function setObjectFormHidden$DebugMode(f, v) {
  $common.setVisible(f.getItem('debug_mode').parentNode.parentNode.parentNode, !v);
  $common.setVisible(f.getItem('adjust_mode').parentNode.parentNode.parentNode, !v);
  if (!v) {
    f._dlgModalPopupBehavior._fixupDropShadowBehavior();
    f._$showDebugMode = true;
    remove$FormDebugMode$KeyupHandler(this);
  }
}
function setItemLive(t1, t2, type) {
  if (type) {if (t2.live) {t1.disabled = false; t1.focus();}}
    else {if (t1.live) {t2.disabled = false; t2.focus();}}
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFieldsEmpty(f, c, v){
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}
/* </flatten> */
